public class DataTypes {
    public static void main(String[] args) {
        byte small = 100;
        short medium = 30000;
        int count = 42;
        long big = 9_000_000_000L;
        float price = 19.99f;
        double precise = 3.14159265;
        char letter = 'Z';
        boolean active = false;

        System.out.println("byte: " + small);
        System.out.println("short: " + medium);
        System.out.println("int: " + count);
        System.out.println("long: " + big);
        System.out.println("float: " + price);
        System.out.println("double: " + precise);
        System.out.println("char: " + letter);
        System.out.println("boolean: " + active);

        double widened = count;
        System.out.println("int to double: " + widened);

        int truncated = (int) precise;
        System.out.println("double to int (cast): " + truncated);
    }
}

